### 5. HELPER FUNCTIONS

#### **formatCurrency(n: number): string**
```typescript
// From: @/lib/utils/format.ts
export function formatCurrency(n: number): string {
  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n.toFixed(2);
}
// Usage: "150K" for 150000, "1.5M" for 1500000, "1234.56" for 1234.56
```

#### **timeUntil(iso: string): string**
```typescript
// From: @/lib/utils/format.ts
export function timeUntil(iso: string): string {
  const diff = new Date(iso).getTime() - Date.now();
  if (diff <= 0) return "expired";
  const hours = Math.floor(diff / 3_600_000);
  const days = Math.floor(hours / 24);
  if (days > 0) return `${days}d ${hours % 24}h`;
  const mins = Math.floor((diff % 3_600_000) / 60_000);
  return `${hours}h ${mins}m`;
}
// Usage: "5d 12h", "3h 45m", "expired"
```

#### **truncateHash(hash: string, len = 8): string**
```typescript
// From: @/lib/utils/format.ts
export function truncateHash(hash: string, len = 8): string {
  if (hash.startsWith("sha256:")) return `sha256:${hash.slice(7, 7 + len)}…`;
  return hash.length > len ? `${hash.slice(0, len)}…` : hash;
}
// Usage: "sha256:abc1234…" or "abcd1234…"
```

#### **formatRelativeTime(iso: string): string**
```typescript
// From: @/lib/utils/format.ts
export function formatRelativeTime(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60_000);
  if (mins < 1) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  return `${days}d ago`;
}
// Usage: "just now", "23m ago", "5h ago", "3d ago"
```

